实验目标：图的建立、遍历及应用设图结点的元素类型为char，建立一个不少于8个顶点的带权无向图G，实现以下图的各种基本操作的程序： 用邻接矩阵作为储结构存储图G并输出该邻接矩阵； 用邻接链表作为储结构存储图G并输出该邻接链表； 按DFS算法输出图G中顶点的遍历序列； 按BFS算法输出图G中顶点的遍历序列； 主函数通过函数调用实现以上各项操作。函数实现部分函数参考了《数据结构-使用C语言》朱战立第6版参数宏定义#include &quot;stdio.h&quot;#include &quot;stdlib.h&quot;#define MAX_VEX 3 //最大顶点数/**********邻接矩阵宏定义**********/#define VexType char //顶点向量，类型可自定义，#define AdjType int //邻接矩阵,权值类型可自定义/**********邻接表宏定义**********/#define InfoType int // 与边或弧相关的信息, 如权值邻接矩阵和邻接表的结构体定义typedef struct{ int vexnum, arcnum; /* 图的当前顶点数和弧数 */ VexType vexs[MAX_VEX]; /* 顶点向量组 */ AdjType adj[MAX_VEX][MAX_VEX]; //邻接矩阵,} MGraph;/* 表结点类型定义 */typedef struct LinkNode{ int adjvex; // 邻接点在头结点数组中的位置(下标) InfoType info; // 与边或弧相关的信息, 如权值 struct LinkNode *nextarc; // 指向下一个表结点} LinkNode;/* 顶点结点类型定义 */typedef struct VexNode{ VexType data; // 顶点信息 int indegree; // 顶点的度, 有向图是入度或出度或没有 LinkNode *firstarc; // 指向第一个表结点} VexNode;/* 图的结构定义 */typedef struct{ int vexnum; //图的当前顶点数 int visited[MAX_VEX]; //访问标志数组,for DFS、BFS VexNode AdjList[MAX_VEX]; //顶点表} ALGraph;邻接矩阵初始化void InitGraph(MGraph *G){ int i, j; G-&amp;gt;vexnum = 0; //初始化顶点数 G-&amp;gt;arcnum = 0; //初始化弧数 for (i = 0; i &amp;lt; MAX_VEX; i++) { for (j = 0; j &amp;lt; MAX_VEX; j++) { if (i == j) G-&amp;gt;adj[i][j] = 0; else G-&amp;gt;adj[i][j] = INT_MAX;//初始化为无穷大 } }}插入顶点void InsertVertex(MGraph *G, VexType Vertex){ if (G-&amp;gt;vexnum &amp;gt; MAX_VEX) { printf(&quot;顶点已满&quot;); return; } G-&amp;gt;vexs[G-&amp;gt;vexnum++] = Vertex;}插入边void InsertEdge(MGraph *G, int v1, int v2, int weight){ if (G-&amp;gt;vexnum &amp;lt; v1 || G-&amp;gt;vexnum &amp;lt; v2||v1&amp;lt;0||v2&amp;lt;0) { printf(&quot;顶点不存在&quot;); return; } G-&amp;gt;adj[v1][v2] = weight; G-&amp;gt;arcnum++;}删除边void DelEdge(MGraph *G, int v1, int v2){ if(G-&amp;gt;vexnum &amp;lt; v1 || G-&amp;gt;vexnum &amp;lt; v2||v1&amp;lt;0||v2&amp;lt;0)//处理越界 { printf(&quot;参数错误&quot;); return; } if(G-&amp;gt;adj[v1][v2]==INT_MAX||v1==v2)//处理越界 { printf(&quot;该边不存在&quot;); return; } G-&amp;gt;adj[v1][v2]=INT_MAX; G-&amp;gt;arcnum--;}图的创建void CreatGraph(MGraph *G){ //先插入顶点 for(int i=0;i&amp;lt;MAX_VEX;i++) { printf(&quot;请输入第%d个顶点的值:&quot;,i+1); scanf(&quot; %c&quot;,&amp;amp;G-&amp;gt;vexs[i]); InsertVertex(G,G-&amp;gt;vexs[i]); } for(int i=0;i&amp;lt;G-&amp;gt;vexnum;i++) { for(int j=0;j&amp;lt;G-&amp;gt;vexnum;j++) { if(i==j) continue;//跳过对角线 printf(&quot;请输入第%d个顶点和第%d个顶点的权值:&quot;,i+1,j+1); scanf(&quot;%d&quot;,&amp;amp;G-&amp;gt;adj[i][j]); InsertEdge(G,i,j,G-&amp;gt;adj[i][j]); } }}输出邻接矩阵void PrintMgraph(MGraph *G){ for(int i=0;i&amp;lt;G-&amp;gt;vexnum+1;i++) { for(int j=0;j&amp;lt;G-&amp;gt;vexnum+1;j++) { if(i==0&amp;amp;&amp;amp;j==0)printf(&quot;	&quot;); else if(i==0&amp;amp;&amp;amp;j!=0)printf(&quot;%c	&quot;,G-&amp;gt;vexs[j-1]);//输出一个好看的矩阵将第一行和第一列化为顶点的信息 else if(i!=0&amp;amp;&amp;amp;j==0)printf(&quot;%c	&quot;,G-&amp;gt;vexs[i-1]); else { printf(&quot;%d	&quot;,G-&amp;gt;adj[i-1][j-1]); } } printf(&quot;
&quot;); }}输出邻接表void PrintAlgraph(ALGraph *G){ for(int i=0;i&amp;lt;G-&amp;gt;vexnum;i++) { printf(&quot;%c &quot;,G-&amp;gt;AdjList[i].data); LinkNode *p=G-&amp;gt;AdjList[i].firstarc; while (p!=NULL) { printf(&quot;-&amp;gt;&quot;); printf(&quot; %c (weight=%d)&quot;,G-&amp;gt;AdjList[p-&amp;gt;adjvex].data,p-&amp;gt;info); p=p-&amp;gt;nextarc; } printf(&quot;
&quot;); }}邻接矩阵转换为邻接表void MGraphToALGraph(MGraph *G, ALGraph *AL){ int i, j; AL-&amp;gt;vexnum = G-&amp;gt;vexnum; //初始化邻接表 for (i = 0; i &amp;lt; MAX_VEX; i++) { AL-&amp;gt;AdjList[i].data = G-&amp;gt;vexs[i]; AL-&amp;gt;AdjList[i].indegree = 0; //初始化入度 AL-&amp;gt;AdjList[i].firstarc = NULL; //第一个表结点先为空 AL-&amp;gt;visited[i] = 0; //初始化访问标志 } //每个顶点计算相连的边，加入LinkNode， for (i = 0; i &amp;lt; G-&amp;gt;vexnum; i++) { for (j = 0; j &amp;lt; G-&amp;gt;vexnum; j++) { if (G-&amp;gt;adj[i][j] != INT_MAX) { LinkNode *p = (LinkNode *)malloc(sizeof(LinkNode)); p-&amp;gt;adjvex = j; //下标 p-&amp;gt;info = G-&amp;gt;adj[i][j]; //权值 //（头插法，将新建的p看作新的头，p-&amp;gt;next连接旧头） p-&amp;gt;nextarc = AL-&amp;gt;AdjList[i].firstarc; //插入到链表头 AL-&amp;gt;AdjList[i].firstarc = p; //更新链表头 AL-&amp;gt;AdjList[j].indegree++; //度数++ } } } return;}dfs算法遍历顶点DFS用邻接表遍历比较方便，一路探到底，采用递归实现，但是可能还是会有爆系统栈的可能性，下次看看采用伪递归实现。void DFS(ALGraph *G, int v)//v为起始{ LinkNode *p; G-&amp;gt;visited[v] = 1; printf(&quot;%c &quot;, G-&amp;gt;AdjList[v].data); p = G-&amp;gt;AdjList[v].firstarc; while (p != NULL) { if (G-&amp;gt;visited[p-&amp;gt;adjvex] == 0) DFS(G, p-&amp;gt;adjvex); p = p-&amp;gt;nextarc; }}bfs算法遍历顶点void BFS(ALGraph *G, int v){ LinkNode *p; int i; G-&amp;gt;visited[v] = 1; printf(&quot;%c &quot;, G-&amp;gt;AdjList[v].data); p = G-&amp;gt;AdjList[v].firstarc; while (p != NULL) { if (G-&amp;gt;visited[p-&amp;gt;adjvex] == 0) { G-&amp;gt;visited[p-&amp;gt;adjvex] = 1; printf(&quot;%c &quot;, G-&amp;gt;AdjList[p-&amp;gt;adjvex].data); } p = p-&amp;gt;nextarc; } for (i = 0; i &amp;lt; G-&amp;gt;vexnum; i++) { if (G-&amp;gt;visited[i] == 0) BFS(G, i); }}清楚访问标志void ClearVisited(ALGraph *G){ for (int i = 0; i &amp;lt; G-&amp;gt;vexnum; i++) G-&amp;gt;visited[i] = 0;}主函数int main(void){ MGraph *MGraph=malloc(sizeof(MGraph)); ALGraph *ALGraph1=malloc(sizeof(ALGraph)); //初始化邻接矩阵 InitGraph(MGraph); //初始化邻接表 CreatGraph(MGraph); //输出邻接矩阵 PrintMgraph(MGraph); printf(&quot;
&quot;); //转换为邻接表 MGraphToALGraph(MGraph,ALGraph1); //输出邻接表 PrintAlgraph(ALGraph1); //dfs算法遍历顶点 printf(&quot;dfs遍历顶点：&quot;); DFS(ALGraph1,0); printf(&quot;
&quot;); //清楚访问标志 ClearVisited(ALGraph1); //bfs算法遍历顶点 printf(&quot;bfs遍历顶点：&quot;); BFS(ALGraph1,0); printf(&quot;
&quot;); return 1;}
